+export type WindowOrderBy = SQLWrapper | SQL.Aliased;
+export interface WindowSpec { partitionBy?: WindowOrderBy | WindowOrderBy[]; orderBy?: WindowOrderBy | WindowOrderBy[]; frame?: WindowFrame; }
+
+type BoundaryKind = 0 | 1 | 2 | 3 | 4;
+export interface WindowBoundary { readonly sql: SQL; readonly kind: BoundaryKind; }
+export interface WindowFrame extends SQLWrapper {}
+
+function boundary(kind: BoundaryKind, text: string): WindowBoundary { return { kind, sql: sql.raw(text) }; }
+export const unboundedPreceding = boundary(0, 'unbounded preceding');
+export const currentRow = boundary(2, 'current row');
+export const unboundedFollowing = boundary(4, 'unbounded following');
+function offsetBoundary(name: string, kind: 1 | 3, value: number): WindowBoundary {
+	if (!Number.isInteger(value) || value < 0) throw new Error(`${name}() requires a non-negative integer, received ${value}`);
+	return boundary(kind, `${value} ${name}`);
+}
+export function preceding(value: number): WindowBoundary { return offsetBoundary('preceding', 1, value); }
+export function following(value: number): WindowBoundary { return offsetBoundary('following', 3, value); }
+function frame(name: string, spec: { from: WindowBoundary; to: WindowBoundary }): WindowFrame {
+	if (spec.from.kind > spec.to.kind) throw new Error('Window frame "from" boundary must not be ordered after "to"');
+	return { getSQL: () => sql`${sql.raw(name)} between ${spec.from.sql} and ${spec.to.sql}` };
+}
+export function rows(spec: { from: WindowBoundary; to: WindowBoundary }): WindowFrame { return frame('rows', spec); }
+export function range(spec: { from: WindowBoundary; to: WindowBoundary }): WindowFrame { return frame('range', spec); }
+
+export class WindowFunction<T> {
+	constructor(private readonly expression: SQL<T>) {}
+	over(spec?: WindowSpec | string): SQL<T> {
+		if (typeof spec === 'string') return sql`${this.expression} over ${sql.identifier(spec)}`;
+		if (!spec) return sql`${this.expression} over ()`;
+		const partitionBy = spec.partitionBy ? (Array.isArray(spec.partitionBy) ? spec.partitionBy : [spec.partitionBy]) : [];
+		const orderBy = spec.orderBy ? (Array.isArray(spec.orderBy) ? spec.orderBy : [spec.orderBy]) : [];
+		const chunks: SQL[] = [];
+		if (partitionBy.length) chunks.push(sql`partition by ${sql.join(partitionBy, sql`, `)}`);
+		if (orderBy.length) chunks.push(sql`order by ${sql.join(orderBy, sql`, `)}`);
+		if (spec.frame) chunks.push(spec.frame.getSQL());
+		return sql`${this.expression} over (${sql.join(chunks, sql` `)})`;
+	}
+}
